import{_ as t,a,b as d,c as n}from"./chunks/授权后复制刷新令牌.DFAJxpN4.js";import{_ as s,o as i,c as o,a2 as l}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Yandex チャンネルの追加","description":"","frontmatter":{},"headers":[],"relativePath":"ja-JP/upload/yandex.md","filePath":"ja-JP/upload/yandex.md","lastUpdated":1781962217000}'),r={name:"ja-JP/upload/yandex.md"};function p(c,e,h,x,b,u){return i(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="yandex-チャンネルの追加" tabindex="-1">Yandex チャンネルの追加 <a class="header-anchor" href="#yandex-チャンネルの追加" aria-label="Permalink to &quot;Yandex チャンネルの追加&quot;">​</a></h1><p>Yandex チャンネルは、Yandex Disk を ImgBed の保存先として利用します。</p><h2 id="事前に用意するもの" tabindex="-1">事前に用意するもの <a class="header-anchor" href="#事前に用意するもの" aria-label="Permalink to &quot;事前に用意するもの&quot;">​</a></h2><table tabindex="0"><thead><tr><th>必要なもの</th><th>用途</th></tr></thead><tbody><tr><td>Yandex アカウント</td><td>Yandex Disk の認証に使います</td></tr><tr><td>Yandex OAuth App</td><td>Client ID と Client Secret を取得します</td></tr><tr><td>ImgBed ドメイン</td><td>OAuth コールバック URL に使います</td></tr><tr><td>Yandex Disk</td><td>実際のファイル保存先</td></tr></tbody></table><h2 id="yandex-oauth-app-を作成する" tabindex="-1">Yandex OAuth App を作成する <a class="header-anchor" href="#yandex-oauth-app-を作成する" aria-label="Permalink to &quot;Yandex OAuth App を作成する&quot;">​</a></h2><p>次の URL を開きます。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://oauth.yandex.com/client/new</span></span></code></pre></div><p>ログインを求められたら、保存先に使う Yandex アカウントでログインします。</p><p>新しいアプリを作成し、分かりやすい名前を付けます。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-yandex</span></span></code></pre></div><p>コールバック URL には次を設定します。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://あなたのドメイン/api/oauth/yandex/callback</span></span></code></pre></div><h2 id="権限を確認する" tabindex="-1">権限を確認する <a class="header-anchor" href="#権限を確認する" aria-label="Permalink to &quot;権限を確認する&quot;">​</a></h2><p>ImgBed の Yandex 連携では、<code>Yandex.Disk REST API</code> の次の権限を使います。</p><table tabindex="0"><thead><tr><th>権限</th><th>用途</th></tr></thead><tbody><tr><td><code>cloud_api:disk.app_folder</code></td><td>アプリフォルダへファイルを保存</td></tr><tr><td><code>cloud_api:disk.read</code></td><td>ファイルとダウンロードリンクを読み取り</td></tr><tr><td><code>cloud_api:disk.write</code></td><td>アップロード、ディレクトリ作成、削除</td></tr><tr><td><code>Access to information about Yandex.Disk</code></td><td>容量と使用量の確認</td></tr></tbody></table><p><code>Yandex ID API</code> の名前やメールアドレスの権限は、必要に応じて選択します。アップロード、削除、容量確認の中心は上記 4 つです。</p><p><img src="'+t+'" alt="Yandex Disk 権限" loading="lazy"></p><h2 id="client-id-と-secret-を控える" tabindex="-1">Client ID と Secret を控える <a class="header-anchor" href="#client-id-と-secret-を控える" aria-label="Permalink to &quot;Client ID と Secret を控える&quot;">​</a></h2><p>アプリ作成後、次の値をコピーします。</p><table tabindex="0"><thead><tr><th>Yandex 側</th><th>ImgBed 側</th></tr></thead><tbody><tr><td><code>Client ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Client Secret</code></td><td><code>Client Secret</code></td></tr></tbody></table><p><img src="'+a+'" alt="Client ID と Secret" loading="lazy"></p><h2 id="imgbed-へ入力する" tabindex="-1">ImgBed へ入力する <a class="header-anchor" href="#imgbed-へ入力する" aria-label="Permalink to &quot;ImgBed へ入力する&quot;">​</a></h2><p>アップロード設定で <code>Yandex</code> を選びます。</p><table tabindex="0"><thead><tr><th>項目</th><th>入力内容</th></tr></thead><tbody><tr><td>チャンネル名</td><td>例：<code>Yandex Main</code></td></tr><tr><td>Client ID</td><td>Yandex App の Client ID</td></tr><tr><td>Client Secret</td><td>Yandex App の Client Secret</td></tr><tr><td>Refresh Token</td><td>まずは空欄</td></tr><tr><td>ルートディレクトリ</td><td>任意。通常は <code>imgbed</code></td></tr></tbody></table><p><img src="'+d+'" alt="Yandex 設定" loading="lazy"></p><h2 id="refresh-token-を取得する" tabindex="-1">Refresh Token を取得する <a class="header-anchor" href="#refresh-token-を取得する" aria-label="Permalink to &quot;Refresh Token を取得する&quot;">​</a></h2><ol><li>ImgBed で「Token を取得」をクリックします。</li><li>保存先に使う Yandex アカウントでログインします。</li><li>権限を許可します。</li><li>コールバックページに表示された <code>Refresh Token</code> をコピーします。</li><li>ImgBed の <code>Refresh Token</code> 欄に貼り付けます。</li></ol><p><img src="'+n+`" alt="Refresh Token" loading="lazy"></p><h2 id="クイック手順" tabindex="-1">クイック手順 <a class="header-anchor" href="#クイック手順" aria-label="Permalink to &quot;クイック手順&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Yandex OAuth Console を開く</span></span>
<span class="line"><span>-&gt; App を作成</span></span>
<span class="line"><span>-&gt; https://あなたのドメイン/api/oauth/yandex/callback を設定</span></span>
<span class="line"><span>-&gt; Disk 権限を確認</span></span>
<span class="line"><span>-&gt; Client ID / Client Secret をコピー</span></span>
<span class="line"><span>-&gt; ImgBed に入力</span></span>
<span class="line"><span>-&gt; Token を取得</span></span>
<span class="line"><span>-&gt; Refresh Token を貼り付けて保存</span></span></code></pre></div><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ol><li>Yandex アプリ登録: <a href="https://yandex.com/dev/id/doc/en/register-client" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/register-client</a></li><li>認可コード URL: <a href="https://yandex.com/dev/id/doc/en/codes/code-url" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/codes/code-url</a></li><li>OAuth Token API: <a href="https://yandex.com/dev/id/doc/en/tokens/token" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/tokens/token</a></li></ol>`,32)])])}const y=s(r,[["render",p]]);export{k as __pageData,y as default};
